import self_coder
import os

# Cargar módulos existentes
from módulo_tabla import tabla
from módulo_conversion import conversion
from módulo_constantes import constantes
from módulo_formula import formula
from módulo_flashcard import flashcard
from módulo_agenda import agenda
from módulo_análisis import análisis

# Función principal del menú de comandos
def menu_comandos():
    while True:
        comando = input("TENSCHI > ")
        if comando == '/salir':
            break
        try:
            comando = comando.split()
            if len(comando) > 1:
                comando = comando[0] + ' ' + comando[1]
            if comando.startswith('/'):
                comando = comando[1:]
            if comando.startswith('tabla'):
                tabla_buscar(comando)
            elif comando.startswith('convertir'):
                conversion_realizar(comando)
            elif comando.startswith('constante'):
                constantes_buscar(comando)
            elif comando.startswith('formula'):
                formula_realizar(comando)
            elif comando.startswith('flashcard'):
                flashcard_realizar(comando)
            elif comando.startswith('agenda'):
                agenda_realizar(comando)
            elif comando.startswith('analizar'):
                análisis_realizar(comando)
            else:
                print("Comando desconocido. Por favor, intenta de nuevo.")
        except Exception as e:
            print(f"Error: {str(e)}")

# Función para buscar en la tabla
def tabla_buscar(comando):
    try:
        comando = comando.split()
        if len(comando) > 1:
            elemento = comando[1]
        else:
            elemento = input("Ingrese el elemento a buscar: ")
        tabla.buscar(elemento)
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para realizar conversiones
def conversion_realizar(comando):
    try:
        comando = comando.split()
        if len(comando) > 2:
            unidad_inicial = comando[1]
            unidad_final = comando[2]
            valor = float(comando[3])
        else:
            unidad_inicial = input("Ingrese la unidad inicial: ")
            unidad_final = input("Ingrese la unidad final: ")
            valor = float(input("Ingrese el valor a convertir: "))
        conversion.realizar(unidad_inicial, unidad_final, valor)
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para buscar constantes
def constantes_buscar(comando):
    try:
        comando = comando.split()
        if len(comando) > 1:
            constante = comando[1]
        else:
            constante = input("Ingrese la constante a buscar: ")
        constantes.buscar(constante)
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para realizar operaciones con fórmulas
def formula_realizar(comando):
    try:
        comando = comando.split()
        if comando[0] == 'guardar':
            formula.guardar()
        elif comando[0] == 'listar':
            formula.listar()
        else:
            print("Comando desconocido. Por favor, intenta de nuevo.")
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para realizar operaciones con flashcards
def flashcard_realizar(comando):
    try:
        comando = comando.split()
        if comando[0] == 'nueva':
            flashcard.nueva()
        elif comando[0] == 'aleatoria':
            flashcard.aleatoria()
        else:
            print("Comando desconocido. Por favor, intenta de nuevo.")
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para realizar operaciones con la agenda
def agenda_realizar(comando):
    try:
        comando = comando.split()
        if comando[0] == 'agregar':
            agenda.agregar()
        elif comando[0] == 'semana':
            agenda.semana()
        else:
            print("Comando desconocido. Por favor, intenta de nuevo.")
    except Exception as e:
        print(f"Error: {str(e)}")

# Función para realizar análisis de datos
def análisis_realizar(comando):
    try:
        comando = comando.split()
        if len(comando) > 1:
            lista = comando[1:]
        else:
            lista = input("Ingrese la lista de números a analizar: ")
            lista = [float(x) for x in lista.split(',')]
        análisis.realizar(lista)
    except Exception as e:
        print(f"Error: {str(e)}")

